import React, { useState } from 'react';
import { TextFieldSlider } from '@salutejs/plasma-web';
export function App() {
    const [value, setValue] = useState(50);
    return (
        <div style={{ display: 'flex', gap: '1rem', flexDirection: 'column' }}>
            <TextFieldSlider
                min={0}
                max={100}
                value={value}
                onChange={(event, values) => setValue(values.raw)}
                hasScale
                titleCaption={`Текущее значение: ${value}`}
            />
        </div>
    );
}

