import React, { useState } from 'react';
import { TextFieldSlider } from '@salutejs/plasma-web';
export function App() {
    const [log, setLog] = useState('');
    return (
        <div style={{ display: 'flex', gap: '1rem', flexDirection: 'column' }}>
            <TextFieldSlider
                min={0}
                max={100}
                defaultValue={50}
                hasScale
                onChange={(event, values) => setLog(`onChange: ${values.formatted}`)}
                onChangeTextField={(values) => setLog(`onChangeTextField: ${values.formatted}`)}
                onChangeSlider={(values) => setLog(`onChangeSlider: ${values.formatted}`)}
                titleCaption="Измените значение"
            />
            <div>Последнее событие: {log}</div>
        </div>
    );
}

